sql:
SELECT agent_id 
  FROM sales 
  WHERE commission = (SELECT MAX(commission) FROM sales);

external_knowledge:
; Past year refers to the last 12 months from the current date; 
; Average asking price is a metric used to evaluate the overall value of properties in a given area or category; 
; Top agent is determined by the number of sales made in the past year, indicating their performance in the real estate market; 
; Top property is the one with the highest sale price, reflecting its value compared to other properties sold in the same period.

sql:
SELECT MAX(offer_price) 
FROM offers
WHERE property_id NOT IN (SELECT property_id FROM sales);

SELECT AVG(property_count) AS average_properties_per_agent
FROM (
    SELECT agent_id, COUNT(property_id) AS property_count
    FROM properties
    GROUP BY agent_id
) AS properties_per_agent;
